import { preloadProfileRoute } from '../../utils/preloadRoutes';

const MobileNavlink = ({ clickOpenSidebar }) => {
    const [showNavlinks, setShowNavlinks] = useState(true);
    const timeOutRef = useRef();
    const navigate = useNavigate();
    const location = useLocation();

    const { user, notifCount, session, openAuthModal } = useAuth();

    const handleNavigatePath = (path) => {
        if (location.pathname === path) {
            return window.location.reload();
        }
        return navigate(path);
    };

    const activeColor = '#5f92ff';
    const inactiveColor = '#787878';

    const navLinks = [
        {
            type: 'profile',
            label: 'Me',
            action: () => {
                if (!session) return openAuthModal();
                preloadProfileRoute();
                clickOpenSidebar();
            },
        },
        {
            type: 'icon',
            label: 'Home',
            path: '/home',
            action: (path) => handleNavigatePath(path),
            icon: (isActive) => (
                <svg xmlns="http://www.w3.org/2000/svg" width="24px" height="24px" viewBox="0 0 24 24" fill={isActive ? activeColor : inactiveColor}>
                    <g clipPath="url(#clip0_1_110)">
                        <path fillRule="evenodd" clipRule="evenodd" d="M14.3594 2.12613C13.0087 0.944612 10.9923 0.94461 9.64162 2.12612L3.2802 7.69086C2.29508 8.55261 1.72998 9.79772 1.72998 11.1066L1.72998 19.1672C1.72998 21.1459 3.33403 22.75 5.31273 22.75L18.6883 22.75C20.667 22.75 22.271 21.1459 22.271 19.1672L22.271 11.1066C22.271 9.79772 21.706 8.55261 20.7208 7.69086L14.3594 2.12613ZM10 16.1136C9.58579 16.1136 9.25 16.4494 9.25 16.8636C9.25 17.2779 9.58579 17.6136 10 17.6136L14 17.6136C14.4142 17.6136 14.75 17.2779 14.75 16.8636C14.75 16.4494 14.4142 16.1136 14 16.1136L10 16.1136Z" fill={isActive ? activeColor : inactiveColor}/>
                    </g>
                </svg>
            ),
        },
        {
            type: 'icon',
            label: 'Explore',
            path: '/home/explore',
            action: (path) => handleNavigatePath(path),
            icon: (isActive) => (
                <svg xmlns="http://www.w3.org/2000/svg" width="24px" height="24px" viewBox="0 0 24 24" fill={isActive ? activeColor : inactiveColor}>
                    <path
                        fillRule="evenodd"
                        d="M12,2 C17.5228475,2 22,6.4771525 22,12 C22,17.5228475 17.5228475,22 12,22 C6.4771525,22 2,17.5228475 2,12 C2,6.4771525 6.4771525,2 12,2 Z M17.9842695,7.39078625 C18.1985588,6.64477525 17.4973604,5.9435768 16.7513494,6.1578661 L16.6494246,6.19284365 L9.57835679,9.02127078 L9.47282273,9.07079854 C9.30957453,9.15937167 9.17428758,9.29167162 9.08209683,9.45256344 L9.02127078,9.57835679 L6.19284365,16.6494246 L6.1578661,16.7513494 C5.9435768,17.4973604 6.64477525,18.1985588 7.39078625,17.9842695 L7.49271102,17.949292 L14.5637788,15.1208648 L14.6693129,15.0713371 C14.8325611,14.982764 14.967848,14.850464 15.0600388,14.6895722 L15.1208648,14.5637788 L17.949292,7.49271102 L17.9842695,7.39078625 Z M12,10 C13.1045695,10 14,10.8954305 14,12 C14,13.1045695 13.1045695,14 12,14 C10.8954305,14 10,13.1045695 10,12 C10,10.8954305 10.8954305,10 12,10 Z"
                    />
                </svg>
            ),
        },
        {
            type: 'icon',
            label: 'Gallery',
            path: '/home/gallery',
            action: (path) => handleNavigatePath(path),
            icon: (isActive) => (
                <svg xmlns="http://www.w3.org/2000/svg" width="24px" height="24px" viewBox="0 0 24 24" fill="none">
                    <path d="M3 6.2C3 4.985 3.985 4 5.2 4H18.8C20.015 4 21 4.985 21 6.2V17.8C21 19.015 20.015 20 18.8 20H5.2C3.985 20 3 19.015 3 17.8V6.2Z" fill={isActive ? activeColor : inactiveColor}/>
                    <path d="M6.8 14.8L8.7 12.7C8.93 12.45 9.32 12.44 9.56 12.67L11.24 14.35L13.72 11.4C13.95 11.12 14.38 11.1 14.64 11.35L17.2 13.85V16.7H4.8V15.8L6.8 14.8Z" fill={isActive ? "#eaf2ff" : "#d8d8d8"} />
                    <circle cx="8.5" cy="8.8" r="1.2" fill={isActive ? "#eaf2ff" : "#d8d8d8"} />
                </svg>
            ),
        },
        {
            type: 'icon',
            label: 'Notifications',
            path: '/home/notifications',
            action: (path) => {
                if (!session) return openAuthModal();
                handleNavigatePath(path);
            },
            notifCount: notifCount > 0 ? notifCount : '',
            icon: (isActive) => (
                <svg xmlns="http://www.w3.org/2000/svg" width="24px" height="24px" viewBox="0 0 24 24" fill={isActive ? activeColor : inactiveColor}>
                    <g>
                        <path fillRule="evenodd" clipRule="evenodd" d="M14.802 19.8317C15.4184 19.7699 15.8349 20.4242 15.5437 20.9539C15.3385 21.3271 15.0493 21.6529 14.7029 21.9197C14.3496 22.1918 13.9397 22.4006 13.5 22.5408C13.0601 22.6812 12.593 22.7522 12.1242 22.7522C11.6554 22.7522 11.1883 22.6812 10.7484 22.5408C10.3087 22.4006 9.89883 22.1918 9.54556 21.9197C9.1991 21.6529 8.90988 21.3271 8.70472 20.9539C8.41354 20.4242 8.83002 19.7699 9.44644 19.8317C9.63869 19.851 11.1433 19.9981 12.1242 19.9981C13.1051 19.9981 14.6097 19.851 14.802 19.8317Z" fill={isActive ? activeColor : inactiveColor}/>
                        <path fillRule="evenodd" clipRule="evenodd" d="M8.52901 2.08755C10.7932 1.00445 13.4465 0.967602 15.7423 1.98737L15.9475 2.07851C18.3532 3.14707 19.8934 5.4622 19.8934 8.0096L19.8934 9.27297C19.8934 10.2885 20.1236 11.2918 20.5681 12.213L20.8335 12.7632C22.0525 15.29 20.465 18.2435 17.6156 18.7498L17.455 18.7783C13.93 19.4046 10.3154 19.4046 6.79044 18.7783C3.90274 18.2653 2.37502 15.1943 3.77239 12.7115L3.99943 12.3082C4.55987 11.3124 4.85335 10.1981 4.85335 9.06596L4.85335 7.79233C4.85335 5.3744 6.27704 3.16478 8.52901 2.08755Z" fill={isActive ? activeColor : inactiveColor}/>
                    </g>
                </svg>
            ),
        },
        {
            type: 'icon',
            label: 'Bookmarks',
            path: '/home/bookmark',
            action: (path) => {
                if (!session) return openAuthModal();
                handleNavigatePath(path);
            },
            icon: (isActive) => (
                <svg xmlns="http://www.w3.org/2000/svg" width="24px" height="24px" viewBox="0 0 24 24" fill="none">
                    <g>
                        <path fillRule="evenodd" clipRule="evenodd" d="M8 1.25C5.37665 1.25 3.25 3.37665 3.25 6V20.4648C3.25 21.7269 4.27311 22.75 5.53518 22.75C5.98634 22.75 6.42739 22.6165 6.80278 22.3662L11.3066 19.3636C11.7265 19.0837 12.2735 19.0837 12.6934 19.3636L17.1972 22.3662C17.5726 22.6165 18.0137 22.75 18.4648 22.75C19.7269 22.75 20.75 21.7269 20.75 20.4648V6C20.75 3.37665 18.6234 1.25 16 1.25H8ZM9 6.75C8.58579 6.75 8.25 7.08579 8.25 7.5C8.25 7.91421 8.58579 8.25 9 8.25H15C15.4142 8.25 15.75 7.91421 15.75 7.5C15.75 7.08579 15.4142 6.75 15 6.75H9Z" fill={isActive ? activeColor : inactiveColor}/>
                    </g>
                </svg>
            ),
        },
    ];

    useEffect(() => {
        const scroll = () => {
            setShowNavlinks(false);

            if (timeOutRef.current) {
                clearTimeout(timeOutRef.current);
            }

            timeOutRef.current = setTimeout(() => {
                setShowNavlinks(true);
            }, 500);
        };

        document.addEventListener('scroll', scroll, true);
        return () => {
            if (timeOutRef.current) {
                clearTimeout(timeOutRef.current);
            }
            document.removeEventListener('scroll', scroll, true);
        };
    }, []);

    return (
        <>
            {showNavlinks && (
                <motion.div
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0, transition: { type: 'spring', stiffness: 300, damping: 25, mass: 0.8 } }}
                    exit={{ opacity: 0, y: 20, transition: { duration: 0.2, ease: 'easeOut' } }}
                    className="mobile-navlink-container"
                >
                    <div className="mobile-navlink-icon-container">
                        {navLinks.map((link, index) => {
                            const isActive = link.path && location.pathname === link.path;

                            if (link.type === 'profile') {
                                return (
                                    <div
                                        key={index}
                                        className="mobile-navlink-item"
                                        onClick={link.action}
                                    >
                                        <div className="mobile-navlink-profile-container">
                                            <img
                                                loading="lazy"
                                                className={`navlink-profile ${session ? 'navlink-profile-active' : ''}`}
                                                src={user?.userData?.[0]?.image_url || '/assets/profile.jpg'}
                                                alt="profile"
                                            />
                                        </div>
                                        <p className={`mobile-navlink-label ${session ? 'mobile-navlink-label-active' : ''}`}>
                                            {link.label}
                                        </p>
                                    </div>
                                );
                            }

                            return (
                                <div
                                    key={index}
                                    className="mobile-navlink-item"
                                    onClick={() => link.action(link.path)}
                                >
                                    <div className="mobile-navlink-icons">
                                        {link.icon(isActive)}
                                        {link.notifCount && (
                                            <div className="notification-count">
                                                {link.notifCount}
                                            </div>
                                        )}
                                    </div>
                                    <p className={`mobile-navlink-label ${isActive ? 'mobile-navlink-label-active' : ''}`}>
                                        {link.label}
                                    </p>
                                    {isActive && <div className="mobile-navlink-active-dot" />}
                                </div>
                            );
                        })}
                    </div>
                </motion.div>
            )}
        </>
    );
};

export default MobileNavlink;
